<template><div class="page"><div class="toolbar"><h1>订单管理</h1><el-select v-model="status" clearable @change="load"><el-option v-for="s in statuses" :key="s" :label="s" :value="s"/></el-select><el-button @click="load">刷新</el-button></div><el-table :data="rows" border><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="userName" label="用户"/><el-table-column prop="driverName" label="司机"/><el-table-column prop="startAddress" label="起点"/><el-table-column prop="endAddress" label="终点"/><el-table-column prop="status" label="状态"/><el-table-column prop="finalAmount" label="金额"/><el-table-column label="操作"><template #default="{row}"><el-button type="danger" @click="cancel(row)">强制取消</el-button></template></el-table-column></el-table></div></template>
<script setup>import {onMounted,ref} from 'vue';import http from '../api/http';const statuses=['WAITING_ACCEPT','ACCEPTED','ARRIVED_LOADING','MOVING','MOVED','COMPLETED','CANCELED'];const status=ref('');const rows=ref([]);async function load(){rows.value=await http.get('/admin/orders',{params:{status:status.value}})}async function cancel(r){await http.post(`/admin/orders/${r.id}/cancel`,{reason:'管理员强制取消'});load()}onMounted(load)</script>
